/**
 * Integration tests for the full analytics pipeline.
 *
 * Tests the complete flow: route handlers → AnalyticsService → repositories → Database.
 * Uses real instances (no mocks) to verify end-to-end correctness.
 */

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import {
  handleGetDashboard,
  handleGetMetric,
  parseAnalyticsQuery,
  parseMetricType,
} from '../../src/routes/analytics.routes.js';
import type { Order } from '../../src/models/order.js';
import type { User } from '../../src/models/user.js';

// ---------------------------------------------------------------------------
// Test helpers
// ---------------------------------------------------------------------------

function makeUser(overrides: Partial<User> & { id: string }): User {
  return {
    name: 'Test User',
    email: `${overrides.id}@example.com`,
    role: 'member',
    createdAt: new Date('2024-01-15'),
    updatedAt: new Date('2024-01-15'),
    ...overrides,
  };
}

function makeOrder(overrides: Partial<Order> & { id: string; userId: string }): Order {
  return {
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 100 }],
    total: 100,
    status: 'confirmed',
    createdAt: new Date('2024-03-15'),
    updatedAt: new Date('2024-03-15'),
    ...overrides,
  };
}

// ---------------------------------------------------------------------------
// Shared setup
// ---------------------------------------------------------------------------

let db: Database;
let orderRepo: OrderRepository;
let userRepo: UserRepository;
let analyticsService: AnalyticsService;

beforeEach(() => {
  db = new Database();
  orderRepo = new OrderRepository(db);
  userRepo = new UserRepository(db);
  analyticsService = new AnalyticsService(orderRepo, userRepo);
});

/**
 * Seed the database with a known dataset for deterministic assertions.
 *
 * Users: alice (created Jan), bob (created Feb), charlie (created Mar)
 * Orders:
 *   - alice: 2 orders in March ($100 confirmed, $200 shipped)
 *   - bob:   1 order in March ($150 pending)
 *   - charlie: 1 order in February ($50 delivered)
 */
function seedData() {
  const alice = makeUser({ id: 'u1', name: 'Alice', createdAt: new Date('2024-01-10') });
  const bob = makeUser({ id: 'u2', name: 'Bob', createdAt: new Date('2024-02-05') });
  const charlie = makeUser({ id: 'u3', name: 'Charlie', createdAt: new Date('2024-03-01') });
  userRepo.save(alice);
  userRepo.save(bob);
  userRepo.save(charlie);

  orderRepo.save(makeOrder({
    id: 'o1', userId: 'u1', total: 100, status: 'confirmed',
    createdAt: new Date('2024-03-10'),
  }));
  orderRepo.save(makeOrder({
    id: 'o2', userId: 'u1', total: 200, status: 'shipped',
    createdAt: new Date('2024-03-20'),
  }));
  orderRepo.save(makeOrder({
    id: 'o3', userId: 'u2', total: 150, status: 'pending',
    createdAt: new Date('2024-03-15'),
  }));
  orderRepo.save(makeOrder({
    id: 'o4', userId: 'u3', total: 50, status: 'delivered',
    createdAt: new Date('2024-02-15'),
  }));
}

// ===========================================================================
// Route-level validation tests
// ===========================================================================

describe('parseAnalyticsQuery', () => {
  it('should parse valid query params', () => {
    const result = parseAnalyticsQuery({
      startDate: '2024-03-01',
      endDate: '2024-04-01',
      granularity: 'day',
    });
    expect(result.startDate).toEqual(new Date('2024-03-01'));
    expect(result.endDate).toEqual(new Date('2024-04-01'));
    expect(result.granularity).toBe('day');
  });

  it('should throw on missing startDate', () => {
    expect(() => parseAnalyticsQuery({ endDate: '2024-04-01' }))
      .toThrow('Missing required query parameter: startDate');
  });

  it('should throw on missing endDate', () => {
    expect(() => parseAnalyticsQuery({ startDate: '2024-03-01' }))
      .toThrow('Missing required query parameter: endDate');
  });

  it('should throw on invalid startDate format', () => {
    expect(() => parseAnalyticsQuery({ startDate: 'not-a-date', endDate: '2024-04-01' }))
      .toThrow('Invalid startDate');
  });

  it('should throw on invalid endDate format', () => {
    expect(() => parseAnalyticsQuery({ startDate: '2024-03-01', endDate: 'nope' }))
      .toThrow('Invalid endDate');
  });

  it('should throw when startDate >= endDate', () => {
    expect(() => parseAnalyticsQuery({
      startDate: '2024-04-01',
      endDate: '2024-03-01',
    })).toThrow('startDate must be before endDate');
  });

  it('should throw on invalid granularity', () => {
    expect(() => parseAnalyticsQuery({
      startDate: '2024-03-01',
      endDate: '2024-04-01',
      granularity: 'yearly',
    })).toThrow('Invalid granularity');
  });

  it('should accept all valid granularities', () => {
    for (const g of ['hour', 'day', 'week', 'month']) {
      const result = parseAnalyticsQuery({
        startDate: '2024-03-01',
        endDate: '2024-04-01',
        granularity: g,
      });
      expect(result.granularity).toBe(g);
    }
  });
});

describe('parseMetricType', () => {
  it('should accept valid metric types', () => {
    expect(parseMetricType('revenue')).toBe('revenue');
    expect(parseMetricType('orders')).toBe('orders');
    expect(parseMetricType('users')).toBe('users');
    expect(parseMetricType('average-order-value')).toBe('average-order-value');
  });

  it('should throw on invalid metric type', () => {
    expect(() => parseMetricType('invalid')).toThrow('Invalid metric type');
  });
});

// ===========================================================================
// Full pipeline: handleGetDashboard
// ===========================================================================

describe('handleGetDashboard — full pipeline', () => {
  beforeEach(seedData);

  it('should return a complete dashboard with all widgets', async () => {
    const dashboard = await handleGetDashboard(analyticsService, {
      startDate: '2024-03-01',
      endDate: '2024-04-01',
    });

    // Metrics: 4 summary cards
    expect(dashboard.metrics).toHaveLength(4);
    const metricTypes = dashboard.metrics.map((m) => m.metricType);
    expect(metricTypes).toContain('revenue');
    expect(metricTypes).toContain('orders');
    expect(metricTypes).toContain('users');
    expect(metricTypes).toContain('average-order-value');

    // Revenue in March: 100 + 200 + 150 = 450
    const revMetric = dashboard.metrics.find((m) => m.metricType === 'revenue')!;
    expect(revMetric.currentValue).toBe(450);

    // Orders in March: 3
    const ordersMetric = dashboard.metrics.find((m) => m.metricType === 'orders')!;
    expect(ordersMetric.currentValue).toBe(3);

    // Users created in March: charlie only
    const usersMetric = dashboard.metrics.find((m) => m.metricType === 'users')!;
    expect(usersMetric.currentValue).toBe(1);

    // Average order value: 450 / 3 = 150
    const aovMetric = dashboard.metrics.find((m) => m.metricType === 'average-order-value')!;
    expect(aovMetric.currentValue).toBe(150);

    // Time series arrays should be present and non-empty
    expect(dashboard.revenueTimeSeries.length).toBeGreaterThan(0);
    expect(dashboard.ordersTimeSeries.length).toBeGreaterThan(0);

    // Order status breakdown: confirmed, shipped, pending
    expect(dashboard.orderStatusBreakdown.length).toBeGreaterThan(0);
    const statuses = dashboard.orderStatusBreakdown.map((b) => b.status);
    expect(statuses).toContain('confirmed');
    expect(statuses).toContain('shipped');
    expect(statuses).toContain('pending');

    // Top users: alice should be first (total $300)
    expect(dashboard.topUsers.length).toBeGreaterThan(0);
    expect(dashboard.topUsers[0].userId).toBe('u1');
    expect(dashboard.topUsers[0].userName).toBe('Alice');
    expect(dashboard.topUsers[0].totalRevenue).toBe(300);

    // Timestamp
    expect(dashboard.generatedAt).toBeInstanceOf(Date);
  });

  it('should respect time-range filtering', async () => {
    // Only February data: charlie's $50 order
    const dashboard = await handleGetDashboard(analyticsService, {
      startDate: '2024-02-01',
      endDate: '2024-03-01',
    });

    const revMetric = dashboard.metrics.find((m) => m.metricType === 'revenue')!;
    expect(revMetric.currentValue).toBe(50);

    const ordersMetric = dashboard.metrics.find((m) => m.metricType === 'orders')!;
    expect(ordersMetric.currentValue).toBe(1);
  });

  it('should return empty data for a date range with no records', async () => {
    const dashboard = await handleGetDashboard(analyticsService, {
      startDate: '2025-01-01',
      endDate: '2025-02-01',
    });

    const revMetric = dashboard.metrics.find((m) => m.metricType === 'revenue')!;
    expect(revMetric.currentValue).toBe(0);

    expect(dashboard.orderStatusBreakdown).toHaveLength(0);
    expect(dashboard.topUsers).toHaveLength(0);
  });

  it('should support custom granularity', async () => {
    const dashboard = await handleGetDashboard(analyticsService, {
      startDate: '2024-03-01',
      endDate: '2024-04-01',
      granularity: 'week',
    });

    // With weekly granularity, March should produce ~5 buckets
    expect(dashboard.revenueTimeSeries.length).toBeLessThanOrEqual(6);
    expect(dashboard.revenueTimeSeries.length).toBeGreaterThanOrEqual(4);

    // Each point should have a label starting with "Week of"
    for (const point of dashboard.revenueTimeSeries) {
      expect(point.label).toMatch(/^Week of/);
    }
  });

  it('should compute period-over-period change percent', async () => {
    // March data vs February data
    const dashboard = await handleGetDashboard(analyticsService, {
      startDate: '2024-03-01',
      endDate: '2024-04-01',
    });

    // Revenue: March=450, February(previous period)=50 → change = (450-50)/50 * 100 = 800%
    const revMetric = dashboard.metrics.find((m) => m.metricType === 'revenue')!;
    expect(revMetric.previousValue).toBe(50);
    expect(revMetric.changePercent).toBe(800);
    expect(revMetric.trend).toBe('up');
  });
});

// ===========================================================================
// Full pipeline: handleGetMetric
// ===========================================================================

describe('handleGetMetric — full pipeline', () => {
  beforeEach(seedData);

  it('should return summary and time series for revenue', async () => {
    const result = await handleGetMetric(analyticsService, 'revenue', {
      startDate: '2024-03-01',
      endDate: '2024-04-01',
    });

    expect(result.summary.metricType).toBe('revenue');
    expect(result.summary.currentValue).toBe(450);
    expect(result.timeSeries.length).toBeGreaterThan(0);
    expect(result.query.metricType).toBe('revenue');
    expect(result.query.granularity).toBe('day');
  });

  it('should return summary and time series for orders', async () => {
    const result = await handleGetMetric(analyticsService, 'orders', {
      startDate: '2024-03-01',
      endDate: '2024-04-01',
    });

    expect(result.summary.currentValue).toBe(3);
  });

  it('should return summary for users metric', async () => {
    const result = await handleGetMetric(analyticsService, 'users', {
      startDate: '2024-03-01',
      endDate: '2024-04-01',
    });

    expect(result.summary.currentValue).toBe(1); // only charlie in March
  });

  it('should return summary for average-order-value', async () => {
    const result = await handleGetMetric(analyticsService, 'average-order-value', {
      startDate: '2024-03-01',
      endDate: '2024-04-01',
    });

    expect(result.summary.currentValue).toBe(150); // 450 / 3
  });

  it('should respect custom granularity', async () => {
    const result = await handleGetMetric(analyticsService, 'revenue', {
      startDate: '2024-03-01',
      endDate: '2024-04-01',
      granularity: 'week',
    });

    expect(result.query.granularity).toBe('week');
    // Weekly buckets for March
    expect(result.timeSeries.length).toBeGreaterThanOrEqual(4);
    expect(result.timeSeries.length).toBeLessThanOrEqual(6);
  });

  it('should reject invalid metric type', async () => {
    await expect(
      handleGetMetric(analyticsService, 'invalid', {
        startDate: '2024-03-01',
        endDate: '2024-04-01',
      }),
    ).rejects.toThrow('Invalid metric type');
  });

  it('should reject missing date params', async () => {
    await expect(
      handleGetMetric(analyticsService, 'revenue', {}),
    ).rejects.toThrow('Missing required query parameter: startDate');
  });
});

// ===========================================================================
// Error scenarios
// ===========================================================================

describe('Error scenarios', () => {
  it('should throw for invalid date params through dashboard handler', async () => {
    await expect(
      handleGetDashboard(analyticsService, { startDate: 'bad', endDate: '2024-04-01' }),
    ).rejects.toThrow('Invalid startDate');
  });

  it('should throw when dates are reversed through dashboard handler', async () => {
    await expect(
      handleGetDashboard(analyticsService, {
        startDate: '2024-04-01',
        endDate: '2024-03-01',
      }),
    ).rejects.toThrow('startDate must be before endDate');
  });

  it('should handle empty database gracefully', async () => {
    // No seed data — database is empty
    const dashboard = await handleGetDashboard(analyticsService, {
      startDate: '2024-03-01',
      endDate: '2024-04-01',
    });

    expect(dashboard.metrics).toHaveLength(4);
    for (const m of dashboard.metrics) {
      expect(m.currentValue).toBe(0);
    }
    expect(dashboard.orderStatusBreakdown).toHaveLength(0);
    expect(dashboard.topUsers).toHaveLength(0);
  });

  it('should handle average-order-value with zero orders (no division by zero)', async () => {
    const result = await handleGetMetric(analyticsService, 'average-order-value', {
      startDate: '2025-01-01',
      endDate: '2025-02-01',
    });

    expect(result.summary.currentValue).toBe(0);
  });
});

// ===========================================================================
// Time series correctness
// ===========================================================================

describe('Time series correctness', () => {
  beforeEach(seedData);

  it('should distribute values across correct daily buckets', async () => {
    const result = await handleGetMetric(analyticsService, 'revenue', {
      startDate: '2024-03-01',
      endDate: '2024-04-01',
      granularity: 'day',
    });

    // March has 31 days
    expect(result.timeSeries).toHaveLength(31);

    // Check that March 10 bucket has alice's $100 order
    const mar10 = result.timeSeries.find((p) => p.label === '2024-03-10');
    expect(mar10).toBeDefined();
    expect(mar10!.value).toBe(100);

    // March 15 has bob's $150
    const mar15 = result.timeSeries.find((p) => p.label === '2024-03-15');
    expect(mar15).toBeDefined();
    expect(mar15!.value).toBe(150);

    // March 20 has alice's $200
    const mar20 = result.timeSeries.find((p) => p.label === '2024-03-20');
    expect(mar20).toBeDefined();
    expect(mar20!.value).toBe(200);

    // A day with no orders should be 0
    const mar01 = result.timeSeries.find((p) => p.label === '2024-03-01');
    expect(mar01).toBeDefined();
    expect(mar01!.value).toBe(0);
  });

  it('should produce monthly buckets', async () => {
    const result = await handleGetMetric(analyticsService, 'revenue', {
      startDate: '2024-01-01',
      endDate: '2024-04-01',
      granularity: 'month',
    });

    expect(result.timeSeries).toHaveLength(3); // Jan, Feb, Mar

    const jan = result.timeSeries.find((p) => p.label === '2024-01');
    expect(jan).toBeDefined();
    expect(jan!.value).toBe(0);

    const feb = result.timeSeries.find((p) => p.label === '2024-02');
    expect(feb).toBeDefined();
    expect(feb!.value).toBe(50);

    const mar = result.timeSeries.find((p) => p.label === '2024-03');
    expect(mar).toBeDefined();
    expect(mar!.value).toBe(450);
  });

  it('should produce hourly buckets for a short range', async () => {
    const result = await handleGetMetric(analyticsService, 'orders', {
      startDate: '2024-03-10T00:00:00.000Z',
      endDate: '2024-03-10T12:00:00.000Z',
      granularity: 'hour',
    });

    expect(result.timeSeries).toHaveLength(12);
  });
});

// ===========================================================================
// Order status breakdown correctness
// ===========================================================================

describe('Order status breakdown', () => {
  beforeEach(seedData);

  it('should compute correct counts and percentages', async () => {
    const dashboard = await handleGetDashboard(analyticsService, {
      startDate: '2024-03-01',
      endDate: '2024-04-01',
    });

    const breakdown = dashboard.orderStatusBreakdown;
    // 3 orders: confirmed, shipped, pending
    expect(breakdown).toHaveLength(3);

    const confirmed = breakdown.find((b) => b.status === 'confirmed')!;
    expect(confirmed.count).toBe(1);
    expect(confirmed.percent).toBeCloseTo(33.33, 1);

    const shipped = breakdown.find((b) => b.status === 'shipped')!;
    expect(shipped.count).toBe(1);

    const pending = breakdown.find((b) => b.status === 'pending')!;
    expect(pending.count).toBe(1);

    // Percentages should sum to 100
    const totalPercent = breakdown.reduce((s, b) => s + b.percent, 0);
    expect(totalPercent).toBeCloseTo(100, 1);
  });
});

// ===========================================================================
// Top users correctness
// ===========================================================================

describe('Top users', () => {
  beforeEach(seedData);

  it('should rank users by revenue descending', async () => {
    const dashboard = await handleGetDashboard(analyticsService, {
      startDate: '2024-03-01',
      endDate: '2024-04-01',
    });

    // alice: $300 (2 orders), bob: $150 (1 order)
    expect(dashboard.topUsers).toHaveLength(2);
    expect(dashboard.topUsers[0].userId).toBe('u1');
    expect(dashboard.topUsers[0].totalRevenue).toBe(300);
    expect(dashboard.topUsers[0].totalOrders).toBe(2);
    expect(dashboard.topUsers[1].userId).toBe('u2');
    expect(dashboard.topUsers[1].totalRevenue).toBe(150);
    expect(dashboard.topUsers[1].totalOrders).toBe(1);
  });

  it('should resolve user names from repository', async () => {
    const dashboard = await handleGetDashboard(analyticsService, {
      startDate: '2024-03-01',
      endDate: '2024-04-01',
    });

    expect(dashboard.topUsers[0].userName).toBe('Alice');
    expect(dashboard.topUsers[1].userName).toBe('Bob');
  });
});

